					uid: '$uid'
				}
			}, {
				_id: {},
				total_users: {
					$sum: 1
				}
			}]
		})

		let eventUserCount = 0
		if (statEventUserRes.data.length > 0) {
			eventUserCount = statEventUserRes.data[0].total_users
		}

		const datetime = new DateTime()
		const insertParams = {
			appid: data._id.appid,
			platform_id: platformInfo._id,
