const maskToken = (token) => {
    if (!token) return '';
    const str = String(token);
    if (str.length <= 12) return `${str.slice(0, 3)}***${str.slice(-2)}`;
    return `${str.slice(0, 6)}...${str.slice(-4)}(len:${str.length})`;
};

async function getUid(event, context) {
    try {
        const ctxUid = context && context.CLIENTINFO && context.CLIENTINFO.uid;
        if (ctxUid) return ctxUid;
        const uniIdCommon = require('uni-id-common');
        const uniID = uniIdCommon.createInstance({ context });
        const token =
            event.uniIdToken ||
            context.uniIdToken ||
            event.token ||
            (event.headers && (event.headers.uniIdToken || event.headers['uni-id-token'])) ||
            (event.params && (event.params.uniIdToken || event.params.token));
        if (!token) return null;
        const payload = await uniID.checkToken(token);
        if (payload.errCode === 0) return payload.uid;
        return null;
    } catch (e) {
        console.error('[fit-discover-api] checkToken error:', e);
        return null;
    }
}

// 计算两点之间距离 (km)
function calcDistance(lat1, lng1, lat2, lng2) {
    const R = 6371; // 地球半径 km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
        Math.sin(dLng / 2) * Math.sin(dLng / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
}

function normalizePoint(locationGeo) {
    if (!locationGeo) return null;
    if (Array.isArray(locationGeo.coordinates) && locationGeo.coordinates.length >= 2) {
        const lng = Number(locationGeo.coordinates[0]);
        const lat = Number(locationGeo.coordinates[1]);
        if (Number.isFinite(lat) && Number.isFinite(lng)) {
            return { lat, lng };
        }
    }
    if (Array.isArray(locationGeo) && locationGeo.length >= 2) {
        const lng = Number(locationGeo[0]);
        const lat = Number(locationGeo[1]);
        if (Number.isFinite(lat) && Number.isFinite(lng)) {
            return { lat, lng };
        }
    }
    return null;
}

const MODERATION_SCENE = Object.freeze({
    FEED: 'feed',
    COMMENT: 'comment',
    INVITE: 'invite',
});
const MODERATION_RESULT = Object.freeze({
    PASS: 'pass',
    REVIEW: 'review',
    BLOCK: 'block',
});
const MODERATION_PRIORITY = {
    [MODERATION_RESULT.PASS]: 0,
    [MODERATION_RESULT.REVIEW]: 1,
    [MODERATION_RESULT.BLOCK]: 2,
};
const MODERATION_CACHE_TTL_MS = 60 * 1000;
const BUILTIN_BLOCK_WORDS = [
    '赌博', '赌局', '网赌', '博彩',
    '代开发票', '假发票',
    '色情', '裸聊', '约炮',
    '枪支', '弹药', '管制刀具',
    '毒品', '冰毒', '大麻', '摇头丸',
    '洗钱', '走私',
];
const BUILTIN_REVIEW_WORDS = [
    '刷单', '兼职打字', '日赚千元', '稳赚不赔',
    '加微信', '加我微信', '加v', '加QQ', '私聊转账',
];
const BUILTIN_BLOCK_REGEX = new RegExp(BUILTIN_BLOCK_WORDS.map(word => word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'), 'i');
const BUILTIN_REVIEW_REGEX = new RegExp(BUILTIN_REVIEW_WORDS.map(word => word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'), 'i');
let securityObjectInitialized = false;
let securityObject = null;
let hasLoggedMissingSecurity = false;
let hasLoggedRuleLoadFailure = false;
let securityRuleCache = { expireAt: 0, rows: [] };

function toTrimmedText(value, maxLength = 500) {
    return String(value || '').trim().slice(0, maxLength);
}

async function callMsgSecCheck(content) {
    if (!content) return null;
    if (uniCloud.security && typeof uniCloud.security.msgSecCheck === 'function') {
        return uniCloud.security.msgSecCheck({ content });
    }
    if (!securityObjectInitialized) {
        securityObjectInitialized = true;
        if (typeof uniCloud.importObject === 'function') {
            try {
                const imported = uniCloud.importObject('security');
                if (imported && typeof imported.msgSecCheck === 'function') {
                    securityObject = imported;
                }
            } catch (error) {
                console.warn('[fit-discover-api] import security object failed:', error);
            }
        }
    }
    if (securityObject && typeof securityObject.msgSecCheck === 'function') {
        return securityObject.msgSecCheck({ content });
    }
    if (!hasLoggedMissingSecurity) {
        hasLoggedMissingSecurity = true;
        console.warn('[fit-discover-api] security.msgSecCheck is unavailable, only fallback keyword checks are active.');
    }
    return null;
}

function pickWorseModeration(currentStatus, nextStatus) {
    return MODERATION_PRIORITY[nextStatus] > MODERATION_PRIORITY[currentStatus] ? nextStatus : currentStatus;
}

function normalizeModerationStatus(status) {
    if (status === MODERATION_RESULT.BLOCK) return MODERATION_RESULT.BLOCK;
    if (status === MODERATION_RESULT.REVIEW) return MODERATION_RESULT.REVIEW;
    return MODERATION_RESULT.PASS;
}

function mapSuggestToModeration(result = {}) {
    const suggest = String(result?.result?.suggest || result?.suggest || result?.data?.result?.suggest || '').toLowerCase();
    if (!suggest || suggest === 'pass' || suggest === 'ok') return MODERATION_RESULT.PASS;
    if (suggest === 'review') return MODERATION_RESULT.REVIEW;
    if (['risky', 'block', 'reject', 'fail'].includes(suggest)) return MODERATION_RESULT.BLOCK;
    return MODERATION_RESULT.REVIEW;
}

function ruleMatchesText(text, rule = {}) {
    const mode = String(rule.match_mode || 'contains').toLowerCase();
    const word = String(rule.word || '').trim();
    if (!word) return false;
    if (mode === 'regex') {
        try {
            return new RegExp(word, 'i').test(text);
        } catch (error) {
            console.warn('[fit-discover-api] invalid security rule regex:', word, error);
            return false;
        }
    }
    if (mode === 'exact') {
        return text.toLowerCase() === word.toLowerCase();
    }
    return text.toLowerCase().includes(word.toLowerCase());
}

async function loadSecurityRules() {
    const now = Date.now();
    if (securityRuleCache.expireAt > now) return securityRuleCache.rows;
    try {
        const res = await securityRulesCol
            .where({ enabled: true })
            .orderBy('priority', 'asc')
            .limit(500)
            .get();
        const rows = Array.isArray(res.data) ? res.data : [];
        securityRuleCache = { expireAt: now + MODERATION_CACHE_TTL_MS, rows };
        return rows;
    } catch (error) {
        if (!hasLoggedRuleLoadFailure) {
            hasLoggedRuleLoadFailure = true;
            console.warn('[fit-discover-api] load security rules failed, fallback to built-in words only:', error);
        }
        securityRuleCache = { expireAt: now + MODERATION_CACHE_TTL_MS, rows: [] };
        return [];
    }
}

async function detectRuleModeration(scene, text) {
    const rules = await loadSecurityRules();
    let moderationStatus = MODERATION_RESULT.PASS;
    let moderationReason = '';
    for (const rule of rules) {
        const ruleScene = String(rule.scene || 'all');
        if (!['all', scene].includes(ruleScene)) continue;
        if (!ruleMatchesText(text, rule)) continue;
        const nextStatus = normalizeModerationStatus(rule.mode);
        if (MODERATION_PRIORITY[nextStatus] > MODERATION_PRIORITY[moderationStatus]) {
            moderationStatus = nextStatus;
            moderationReason = `${nextStatus === MODERATION_RESULT.BLOCK ? '命中拦截词' : '命中审核词'}:${rule.word}`;
        }
        if (moderationStatus === MODERATION_RESULT.BLOCK) break;
    }
    return { moderationStatus, moderationReason };
}

async function evaluateTextModeration(rawText, options = {}) {
    const { scene, fieldName = '内容', allowEmpty = true, maxLength = 500 } = options;
    const text = toTrimmedText(rawText, maxLength);
    if (!text) {
        if (allowEmpty) {
            return { text: '', moderationStatus: MODERATION_RESULT.PASS, moderationReason: '' };
        }
        throw new Error(`${fieldName}不能为空`);
    }

    let moderationStatus = MODERATION_RESULT.PASS;
    let moderationReason = '';

    if (BUILTIN_BLOCK_REGEX.test(text)) {
        moderationStatus = MODERATION_RESULT.BLOCK;
        moderationReason = '命中系统拦截词';
    } else if (BUILTIN_REVIEW_REGEX.test(text)) {
        moderationStatus = MODERATION_RESULT.REVIEW;
        moderationReason = '命中系统审核词';
    }

    const ruleResult = await detectRuleModeration(scene, text);
    if (MODERATION_PRIORITY[ruleResult.moderationStatus] > MODERATION_PRIORITY[moderationStatus]) {
        moderationStatus = ruleResult.moderationStatus;
        moderationReason = ruleResult.moderationReason;
    }

    try {
        const secRes = await callMsgSecCheck(text);
        if (!secRes) return { text, moderationStatus, moderationReason };
        if (typeof secRes.errCode === 'number' && secRes.errCode !== 0) {
            console.error('[fit-discover-api] msgSecCheck error:', secRes);
            throw new Error('内容安全校验失败，请稍后重试');
        }
        const msgSecStatus = mapSuggestToModeration(secRes);
        if (MODERATION_PRIORITY[msgSecStatus] > MODERATION_PRIORITY[moderationStatus]) {
            moderationStatus = msgSecStatus;
            moderationReason = `云端审核:${msgSecStatus}`;
        }
    } catch (error) {
        console.error('[fit-discover-api] msgSecCheck failed:', error);
        throw new Error('内容安全校验失败，请稍后重试');
    }

    return {
        text,
        moderationStatus,
        moderationReason: moderationReason.slice(0, 200),
    };
}

async function evaluateModerationBatch(scene, fields = []) {
    const sanitized = {};
    let moderationStatus = MODERATION_RESULT.PASS;
    let moderationReason = '';

    for (const field of fields) {
        const result = await evaluateTextModeration(field.value, {
            scene,
            fieldName: field.fieldName,
            allowEmpty: field.allowEmpty !== false,
            maxLength: field.maxLength || 500,
        });
        sanitized[field.key] = result.text;
        if (MODERATION_PRIORITY[result.moderationStatus] > MODERATION_PRIORITY[moderationStatus]) {
            moderationStatus = result.moderationStatus;
            moderationReason = result.moderationReason;
        }
        if (moderationStatus === MODERATION_RESULT.BLOCK) break;
    }

    return {
        moderationStatus,
        moderationReason: String(moderationReason || '').slice(0, 200),
        sanitized,
    };
}

function mapFeedStatusByModeration(moderationStatus) {
    return moderationStatus === MODERATION_RESULT.REVIEW ? 0 : 1;
}

function mapCommentStatusByModeration(moderationStatus) {
    return moderationStatus === MODERATION_RESULT.REVIEW ? 0 : 1;
}

async function ensureFeedVisible(feedId, requestUid, options = {}) {
    const { requirePublished = false, allowOwnerWhenHidden = true, failMessage = '动态不可见' } = options;
    const feedRes = await feedsCol.doc(feedId).get();
    if (!feedRes.data || feedRes.data.length === 0) {
        throw new Error('动态不存在');
    }
    const feed = feedRes.data[0];
    const status = Number(feed.status);
    if (requirePublished && status !== 1) {
        throw new Error(failMessage);
    }
    if (status !== 1) {
        const isOwner = !!requestUid && feed.user_id === requestUid;
        if (!(allowOwnerWhenHidden && isOwner)) {
            throw new Error(failMessage);
        }
    }
    return feed;
}

exports.main = async (event, context) => {
    const { action, params = {} } = event;
    let uid = context.CLIENTINFO?.uid || null;
    const requireAuth = async () => {
        if (!uid) uid = await getUid(event, context);
        return uid;
    };

    try {
        switch (action) {
            // ==================== Feed 列表 ====================
            case 'getFeedList': {
                const { page = 1, pageSize = 10, gender, type, level, distanceKm, lat, lng, userId, status } = params;
                const normalizedPage = Math.max(Number(page) || 1, 1);
                const normalizedPageSize = Math.min(Math.max(Number(pageSize) || 10, 1), 50);
                const skip = (normalizedPage - 1) * normalizedPageSize;
                const requestLat = Number(lat);
                const requestLng = Number(lng);
                const maxDistance = Number(distanceKm);
                const hasRequesterPoint = Number.isFinite(requestLat) && Number.isFinite(requestLng);
                const hasDistanceFilter = Number.isFinite(maxDistance);

                let query = {};
                const authedUid = userId ? await requireAuth() : uid;
                const queryingOwnFeeds = !!userId && !!authedUid && userId === authedUid;

                if (userId) {
                    query.user_id = userId;
                }

                if (queryingOwnFeeds) {
                    const numericStatus = Number(status);
                    if ([0, 1, 2].includes(numericStatus)) {
                        query.status = numericStatus;
                    }
                } else {
                    query.status = 1;
                }
                
                // 筛选条件
                if (gender && gender !== 'all') {
                    query.gender = gender;
                }
                if (type && type !== 'all') {
                    query.type = type;
                }
                if (level && level !== 'all') {
                    query.level = level;
                }

                let list = [];
                let total = 0;

                if (!hasRequesterPoint) {
                    const [feedRes, totalRes] = await Promise.all([
                        feedsCol
                            .where(query)
                            .orderBy('create_date', 'desc')
                            .skip(skip)
                            .limit(normalizedPageSize)
                            .get(),
                        feedsCol.where(query).count(),
                    ]);
                    list = feedRes.data || [];
                    total = totalRes.total || 0;
                } else {
                    const batchSize = Math.max(normalizedPageSize * 3, 100);
                    let cursor = 0;
                    let filteredList = [];

                    while (true) {
                        const batchRes = await feedsCol
                            .where(query)
                            .orderBy('create_date', 'desc')
                            .skip(cursor)
                            .limit(batchSize)
                            .get();

                        const batch = batchRes.data || [];
                        if (batch.length === 0) break;

                        const mapped = batch.map(feed => {
                            let distanceVal = null;
                            const point = normalizePoint(feed.location_geo);
                            if (point) {
                                distanceVal = calcDistance(requestLat, requestLng, point.lat, point.lng);
                            }
                            return { ...feed, distanceKm: distanceVal };
                        });

                        const passed = hasDistanceFilter
                            ? mapped.filter(item => item.distanceKm === null || item.distanceKm <= maxDistance)
                            : mapped;
                        filteredList.push(...passed);

                        cursor += batch.length;
                        if (batch.length < batchSize) break;
                    }

                    filteredList.sort((a, b) => {
                        const aDistance = Number.isFinite(a.distanceKm) ? a.distanceKm : Number.MAX_SAFE_INTEGER;
                        const bDistance = Number.isFinite(b.distanceKm) ? b.distanceKm : Number.MAX_SAFE_INTEGER;
                        if (aDistance !== bDistance) return aDistance - bDistance;

                        const aCreate = Number(a.create_date || 0);
                        const bCreate = Number(b.create_date || 0);
                        if (aCreate !== bCreate) return bCreate - aCreate;

                        return String(a._id || '').localeCompare(String(b._id || ''));
                    });

                    total = filteredList.length;
                    list = filteredList.slice(skip, skip + normalizedPageSize);
                }

                // 如果用户已登录，获取点赞和收藏状态（仅查询当前页）
                if (uid && list.length > 0) {
                    const feedIds = list.map(f => f._id).filter(Boolean);
                    if (feedIds.length > 0) {
                        const [likesRes, collectsRes] = await Promise.all([
                            likesCol.where({ user_id: uid, feed_id: dbCmd.in(feedIds) }).get(),
                            collectsCol.where({ user_id: uid, feed_id: dbCmd.in(feedIds) }).get()
                        ]);

                        const likedSet = new Set((likesRes.data || []).map(l => l.feed_id));
                        const collectedSet = new Set((collectsRes.data || []).map(c => c.feed_id));

                        list = list.map(feed => ({
                            ...feed,
                            liked: likedSet.has(feed._id),
                            collected: collectedSet.has(feed._id)
                        }));
                    }
                }

                // 格式化输出
                const formattedList = list.map(feed => ({
                    id: feed._id,
                    userId: feed.user_id,
                    nickname: feed.nickname || '用户',
                    avatar: feed.avatar || '',
                    gender: feed.gender || 'unknown',
                    cover: feed.cover || '',
                    content: feed.content,
                    type: feed.type,
                    level: feed.level,
                    location: feed.location || '',
                    distanceKm: feed.distanceKm != null ? Number(feed.distanceKm.toFixed(2)) : null,
                    tags: feed.tags || [],
                    status: typeof feed.status === 'number' ? feed.status : 1,
                    moderationStatus: feed.moderation_status || 'pass',
                    moderationReason: feed.moderation_reason || '',
                    likeCount: feed.like_count || 0,
                    commentCount: feed.comment_count || 0,
                    giftCount: feed.gift_count || 0,
                    liked: feed.liked || false,
                    collected: feed.collected || false,
                    createdAt: feed.create_date
                }));

                // 计算是否还有更多
                const hasMore = skip + list.length < total;

                return success({ list: formattedList, hasMore, total });
            }

            // ==================== 公开用户主页 ====================
            case 'getPublicProfile': {
                const { userId } = params;
                if (!userId) return fail('参数错误');

                let base = { nickname: '用户', avatar: '', gender: '', age: null };
                try {
                    const userRes = await usersCol.doc(userId).field({
                        nickname: 1,
                        avatar: 1,
                        gender: 1,
                        avatar_file: 1,
                    }).get();
                    if (userRes.data && userRes.data.length > 0) {
                        const u = userRes.data[0];
                        base = {
                            nickname: u.nickname || '用户',
                            avatar: u.avatar || (u.avatar_file && u.avatar_file.url) || '',
                            gender: u.gender || '',
                            age: null,
                        };
                    }
                } catch (e) {
                    console.warn('[fit-discover-api] getPublicProfile userRes failed:', e);
                }

                let extra = { coverUrl: '', bio: '', gyms: [], gender: '', age: null };
                try {
                    const profRes = await profilesCol.where({ uid: userId }).limit(1).get();
                    if (profRes.data && profRes.data.length > 0) {
                        const p = profRes.data[0];
                        extra = {
                            coverUrl: p.cover_url || '',
                            bio: p.bio || '',
                            gyms: Array.isArray(p.gyms) ? p.gyms : [],
                            gender: p.gender || '',
                            age: typeof p.age === 'number' ? p.age : null,
                        };
                    }
                } catch (e) {
                    console.warn('[fit-discover-api] getPublicProfile profileRes failed:', e);
                }

                return success({
                    userId,
                    nickname: base.nickname,
                    avatarUrl: base.avatar,
                    coverUrl: extra.coverUrl,
                    bio: extra.bio,
                    gyms: extra.gyms,
                    gender: extra.gender || base.gender || '',
                    age: extra.age,
                });
            }

            // ==================== 发布动态 ====================
            case 'publishFeed': {
                const authedUid = await requireAuth();
                if (!authedUid) return fail('请先登录');

                const { content, type, location, photo, tags, lat, lng, level, gender, location_geo } = params;
                const safeTags = Array.isArray(tags)
                    ? tags.map(tag => toTrimmedText(tag, 30)).filter(Boolean).slice(0, 10)
                    : [];
                const moderation = await evaluateModerationBatch(MODERATION_SCENE.FEED, [
                    { key: 'content', value: content, fieldName: '动态内容', allowEmpty: false, maxLength: 500 },
                    { key: 'location', value: location, fieldName: '地点', allowEmpty: true, maxLength: 100 },
                    { key: 'tags', value: safeTags.join(' '), fieldName: '标签', allowEmpty: true, maxLength: 300 },
                ]);
                if (moderation.moderationStatus === MODERATION_RESULT.BLOCK) {
                    return fail('动态内容包含违规信息，请修改后重试');
                }
                const safeContent = moderation.sanitized.content;
                const safeLocation = moderation.sanitized.location;

                // 获取用户信息
                let userInfo = { nickname: '用户', avatar: '', gender: 'unknown' };
                const userRes = await usersCol.doc(authedUid).field({ nickname: 1, avatar: 1, gender: 1, avatar_file: 1 }).get();
                if (userRes.data && userRes.data.length > 0) {
                    userInfo = userRes.data[0];
                }

                let geo = location_geo || null;
                if (!geo && lat && lng) {
                    geo = { type: 'Point', coordinates: [lng, lat] };
                }

                const now = Date.now();
                const feedData = {
                    user_id: authedUid,
                    nickname: userInfo.nickname || '用户',
                    avatar: userInfo.avatar || (userInfo.avatar_file && userInfo.avatar_file.url) || '',
                    gender: userInfo.gender || gender || 'unknown',
                    cover: photo || '',
                    content: safeContent,
                    type: type || 'gym',
                    level: level || 'beginner',
                    location: safeLocation,
                    location_geo: geo,
                    tags: safeTags,
                    like_count: 0,
                    comment_count: 0,
                    gift_count: 0,
                    status: mapFeedStatusByModeration(moderation.moderationStatus),
                    moderation_status: moderation.moderationStatus,
                    moderation_reason: moderation.moderationReason || '',
                    moderation_updated_at: now,
                    create_date: now
                };

                const addRes = await feedsCol.add(feedData);

                return success({
                    id: addRes.id,
                    ...feedData,
                    likeCount: 0,
                    commentCount: 0,
                    giftCount: 0,
                    liked: false,
                    collected: false,
                    moderationStatus: moderation.moderationStatus,
                }, moderation.moderationStatus === MODERATION_RESULT.REVIEW ? '内容已提交审核' : '发布成功');
            }

            case 'updateFeed': {
                const authedUid = await requireAuth();
                if (!authedUid) return fail('请先登录');

                const { feedId, content, type, location, photo, tags, lat, lng, level, gender, location_geo } = params;
                if (!feedId) return fail('参数错误');

                const existing = await feedsCol.doc(feedId).get();
                if (!existing.data || existing.data.length === 0) return fail('动态不存在');
                const row = existing.data[0];
                if (row.user_id !== authedUid) return fail('无权限');

                let geo = location_geo || null;
                if (!geo && lat && lng) {
                    geo = { type: 'Point', coordinates: [lng, lat] };
                }

                const safeTags = tags !== undefined
                    ? (Array.isArray(tags) ? tags.map(tag => toTrimmedText(tag, 30)).filter(Boolean).slice(0, 10) : [])
                    : undefined;
                const moderationFields = [];
                if (content !== undefined) {
                    moderationFields.push({ key: 'content', value: content, fieldName: '动态内容', allowEmpty: false, maxLength: 500 });
                }
                if (location !== undefined) {
                    moderationFields.push({ key: 'location', value: location, fieldName: '地点', allowEmpty: true, maxLength: 100 });
                }
                if (safeTags !== undefined) {
                    moderationFields.push({ key: 'tags', value: safeTags.join(' '), fieldName: '标签', allowEmpty: true, maxLength: 300 });
                }
                const moderation = moderationFields.length > 0
                    ? await evaluateModerationBatch(MODERATION_SCENE.FEED, moderationFields)
                    : { moderationStatus: MODERATION_RESULT.REVIEW, moderationReason: '内容更新待审核', sanitized: {} };
                if (moderation.moderationStatus === MODERATION_RESULT.BLOCK) {
                    return fail('动态内容包含违规信息，请修改后重试');
                }

                const updateData = { update_date: Date.now() };
                if (content !== undefined) {
                    updateData.content = moderation.sanitized.content;
                }
                if (type !== undefined) updateData.type = type;
                if (level !== undefined) updateData.level = level;
                if (gender !== undefined) updateData.gender = gender;
                if (location !== undefined) {
                    updateData.location = moderation.sanitized.location;
                }
                if (photo !== undefined) updateData.cover = photo;
                if (safeTags !== undefined) updateData.tags = safeTags;
                if (geo !== undefined) updateData.location_geo = geo;
                updateData.status = mapFeedStatusByModeration(moderation.moderationStatus);
                updateData.moderation_status = moderation.moderationStatus;
                updateData.moderation_reason = moderation.moderationReason || '';
                updateData.moderation_updated_at = Date.now();

                await feedsCol.doc(feedId).update(updateData);
                return success({
                    msg: moderation.moderationStatus === MODERATION_RESULT.REVIEW ? '更新成功，内容审核中' : '更新成功',
                    moderationStatus: moderation.moderationStatus,
                });
            }

            case 'getMyFeedStats': {
                const authedUid = await requireAuth();
                if (!authedUid) return fail('请先登录');

                const [pendingRes, publishedRes, deletedRes] = await Promise.all([
                    feedsCol.where({ user_id: authedUid, status: 0 }).count(),
                    feedsCol.where({ user_id: authedUid, status: 1 }).count(),
                    feedsCol.where({ user_id: authedUid, status: 2 }).count(),
                ]);

                const pending = pendingRes.total || 0;
                const published = publishedRes.total || 0;
                const deleted = deletedRes.total || 0;

                return success({
                    pending,
                    published,
                    deleted,
                    total: pending + published + deleted,
                    active: pending + published,
                });
            }

            case 'removeFeed': {
                const authedUid = await requireAuth();
                if (!authedUid) return fail('请先登录');

                const { feedId } = params;
                if (!feedId) return fail('参数错误');

                const existing = await feedsCol.doc(feedId).get();
                if (!existing.data || existing.data.length === 0) return fail('动态不存在');
                const row = existing.data[0];
                if (row.user_id !== authedUid) return fail('无权限');

                await feedsCol.doc(feedId).update({
                    status: 2,
                    update_date: Date.now()
                });
                return success({ msg: '删除成功' });
            }

            // ==================== 点赞/取消点赞 ====================
            case 'likeFeed': {
                const likeUid = await requireAuth();
                if (!likeUid) return fail('请先登录');

                const { feedId, liked } = params;
                if (!feedId) return fail('参数错误');

                if (liked) {
                    // 点赞
                    const existingLike = await likesCol.where({ feed_id: feedId, user_id: uid }).get();
                    if (existingLike.data.length === 0) {
                        await likesCol.add({
                            feed_id: feedId,
                            user_id: uid,
                            create_date: Date.now()
                        });
                        await feedsCol.doc(feedId).update({ like_count: dbCmd.inc(1) });
                    }
                } else {
                    // 取消点赞
                    await likesCol.where({ feed_id: feedId, user_id: uid }).remove();
                    await feedsCol.doc(feedId).update({ like_count: dbCmd.inc(-1) });
                }

                return success({ liked });
            }

            // ==================== 收藏/取消收藏 ====================
            case 'collectFeed': {
                const collectUid = await requireAuth();
                if (!collectUid) return fail('请先登录');

                const { feedId, collected } = params;
                if (!feedId) return fail('参数错误');

                if (collected) {
                    const existingCollect = await collectsCol.where({ feed_id: feedId, user_id: uid }).get();
                    if (existingCollect.data.length === 0) {
                        await collectsCol.add({
                            feed_id: feedId,
                            user_id: uid,
                            create_date: Date.now()
                        });
                    }
                } else {
                    await collectsCol.where({ feed_id: feedId, user_id: uid }).remove();
                }

                return success({ collected });
            }

            // ==================== 发表评论 ====================
            case 'addComment': {
                const commentUid = await requireAuth();
                if (!commentUid) return fail('请先登录');

                const { feedId, content, replyTo } = params;
                if (!feedId || !content || content.trim().length === 0) {
                    return fail('参数错误');
                }
                await ensureFeedVisible(feedId, commentUid, { requirePublished: true, allowOwnerWhenHidden: false, failMessage: '动态不可评论' });
                const moderation = await evaluateModerationBatch(MODERATION_SCENE.COMMENT, [
                    { key: 'content', value: content, fieldName: '评论内容', allowEmpty: false, maxLength: 200 },
                ]);
                if (moderation.moderationStatus === MODERATION_RESULT.BLOCK) {
                    return fail('评论内容包含违规信息，请修改后重试');
                }
                const safeComment = moderation.sanitized.content;

                // 获取用户信息
                let userInfo = { nickname: '用户', avatar: '' };
                const userRes = await usersCol.doc(commentUid).field({ nickname: 1, avatar: 1 }).get();
                if (userRes.data && userRes.data.length > 0) {
                    userInfo = userRes.data[0];
                }

                const commentData = {
                    feed_id: feedId,
                    user_id: commentUid,
                    nickname: userInfo.nickname,
                    avatar: userInfo.avatar,
                    content: safeComment,
                    reply_to: replyTo || null,
                    status: mapCommentStatusByModeration(moderation.moderationStatus),
                    moderation_status: moderation.moderationStatus,
                    moderation_reason: moderation.moderationReason || '',
                    moderation_updated_at: Date.now(),
                    create_date: Date.now()
                };

                await commentsCol.add(commentData);
                if (commentData.status === 1) {
                    await feedsCol.doc(feedId).update({ comment_count: dbCmd.inc(1) });
                }

                return success(commentData, moderation.moderationStatus === MODERATION_RESULT.REVIEW ? '评论已提交审核' : '评论成功');
            }

            // ==================== 获取评论列表 ====================
            case 'getComments': {
                const { feedId, page = 1, pageSize = 20 } = params;
                if (!feedId) return fail('参数错误');
                const viewerUid = await requireAuth();
                await ensureFeedVisible(feedId, viewerUid, { allowOwnerWhenHidden: true, failMessage: '动态不可见' });

                const skip = (page - 1) * pageSize;
                const res = await commentsCol
                    .where({ feed_id: feedId, status: 1 })
                    .orderBy('create_date', 'desc')
                    .skip(skip)
                    .limit(pageSize)
                    .get();

                return success(res.data || []);
            }

            // ==================== 送礼物 ====================
            case 'sendGift': {
                const giftUid = await requireAuth();
                if (!giftUid) return fail('请先登录');

                const { feedId, toUserId, giftCode } = params;
                if (!feedId || !toUserId || !giftCode) {
                    return fail('参数错误');
                }

                const giftValues = { drink: 1, protein: 5, relax: 10, rose: 20 };
                const giftValue = giftValues[giftCode] || 1;

                await giftsCol.add({
                    feed_id: feedId,
                    from_user_id: uid,
                    to_user_id: toUserId,
                    gift_code: giftCode,
                    gift_value: giftValue,
                    create_date: Date.now()
                });

                await feedsCol.doc(feedId).update({ gift_count: dbCmd.inc(1) });

                return success({ giftCode, giftValue });
            }

            // ==================== 发送约练邀请 ====================
            case 'sendInvite': {
                const inviteUid = await requireAuth();
                if (!inviteUid) return fail('请先登录');

                const { feedId, toUserId, toNickname, date, place, message } = params;
                const safeDate = toTrimmedText(date, 40);
                const safePlace = toTrimmedText(place, 100);
                const safeMessage = toTrimmedText(message, 200);
                const safeToNickname = toTrimmedText(toNickname, 50);
                if (!toUserId || !safeDate || !safePlace) {
                    return fail('请填写完整的约练信息');
                }
                const moderation = await evaluateModerationBatch(MODERATION_SCENE.INVITE, [
                    { key: 'date', value: safeDate, fieldName: '邀约日期', allowEmpty: false, maxLength: 40 },
                    { key: 'place', value: safePlace, fieldName: '邀约地点', allowEmpty: false, maxLength: 100 },
                    { key: 'message', value: safeMessage, fieldName: '邀约留言', allowEmpty: true, maxLength: 200 },
                    { key: 'toNickname', value: safeToNickname, fieldName: '邀约对象昵称', allowEmpty: true, maxLength: 50 },
                ]);
                if (moderation.moderationStatus === MODERATION_RESULT.BLOCK) {
                    return fail('邀约内容包含违规信息，请修改后重试');
                }
                if (feedId) {
                    await ensureFeedVisible(feedId, inviteUid, {
                        requirePublished: true,
                        allowOwnerWhenHidden: false,
                        failMessage: '该动态不可发起邀约',
                    });
                }

                // 获取发起者信息
                let fromInfo = { nickname: '用户', avatar: '' };
                const fromRes = await usersCol.doc(inviteUid).field({ nickname: 1, avatar: 1 }).get();
                if (fromRes.data && fromRes.data.length > 0) {
                    fromInfo = fromRes.data[0];
                }

                const inviteData = {
                    feed_id: feedId || null,
                    from_user_id: inviteUid,
                    from_nickname: fromInfo.nickname,
                    from_avatar: fromInfo.avatar,
                    to_user_id: toUserId,
                    to_nickname: safeToNickname,
                    date: safeDate,
                    place: safePlace,
                    message: safeMessage,
                    moderation_status: moderation.moderationStatus,
                    moderation_reason: moderation.moderationReason || '',
                    moderation_updated_at: Date.now(),
                    status: 0,
                    create_date: Date.now()
                };

                const addRes = await invitesCol.add(inviteData);

                // >>> 发送通知给对方 <<<
                if (moderation.moderationStatus === MODERATION_RESULT.PASS) {
                    try {
                        await notificationsCol.add({
                            toUserId,
                            fromUserId: inviteUid,
                            type: 'apply',
                            title: '新的约练邀请',
                            content: `${fromInfo.nickname} 邀请你一起${safeDate}在${safePlace}约练`,
                            meetId: feedId || '',
                            meetTitle: `${safeDate} · ${safePlace}`,
                            isRead: false,
                            readAt: null,
                            createdAt: Date.now(),
                        });
                    } catch (e) {
                        console.warn('[fit-discover-api] create invite notification failed:', e);
                    }
                }

                return success(
                    { id: addRes.id, moderationStatus: moderation.moderationStatus },
                    moderation.moderationStatus === MODERATION_RESULT.REVIEW ? '邀约已提交审核' : '约练邀请已发送'
                );
            }

            // ==================== 获取我的约练邀请 ====================
            case 'getMyInvites': {
                const myInvitesUid = await requireAuth();
                if (!myInvitesUid) return fail('请先登录');

                const { type = 'received', page = 1, pageSize = 20 } = params;
                const skip = (page - 1) * pageSize;

                let query = {};
                if (type === 'received') {
                    query.to_user_id = myInvitesUid;
                    query.moderation_status = dbCmd.neq(MODERATION_RESULT.REVIEW);
                } else {
                    query.from_user_id = myInvitesUid;
                }

                const res = await invitesCol
                    .where(query)
                    .orderBy('create_date', 'desc')
                    .skip(skip)
                    .limit(pageSize)
                    .get();

                return success(res.data || []);
            }

            // ==================== 处理约练邀请 ====================
            case 'handleInvite': {
                const handleUid = await requireAuth();
                if (!handleUid) return fail('请先登录');

                const { inviteId, status } = params; // status: 1=接受, 2=拒绝
                if (!inviteId || ![1, 2].includes(status)) {
                    return fail('参数错误');
                }

                // 验证是被邀请者
                const inviteRes = await invitesCol.doc(inviteId).get();
                if (!inviteRes.data || inviteRes.data.length === 0) {
                    return fail('邀请不存在');
                }
                
                const invite = inviteRes.data[0];
                if (invite.to_user_id !== handleUid) {
                    return fail('无权操作');
                }
                if (invite.moderation_status === MODERATION_RESULT.REVIEW) {
                    return fail('邀约正在审核中，暂不可处理');
                }

                await invitesCol.doc(inviteId).update({
                    status: status,
                    update_date: Date.now()
                });

                // >>> 发送通知给邀请发起者 <<<
                try {
                    const toNickname = invite.to_nickname || '用户';
                    const nType = status === 1 ? 'accepted' : 'rejected';
                    const nTitle = status === 1 ? '约练邀请已接受' : '约练邀请未通过';
                    const nContent = status === 1
                        ? `${toNickname} 接受了你的约练邀请`
                        : `${toNickname} 未能接受你的约练邀请`;
                    await notificationsCol.add({
                        toUserId: invite.from_user_id,
                        fromUserId: handleUid,
                        type: nType,
                        title: nTitle,
                        content: nContent,
                        meetId: invite.feed_id || '',
                        meetTitle: `${invite.date || ''} · ${invite.place || ''}`,
                        isRead: false,
                        readAt: null,
                        createdAt: Date.now(),
                    });
                } catch (e) {
                    console.warn('[fit-discover-api] create handleInvite notification failed:', e);
                }

                return success({ status });
            }

            // ==================== 获取动态详情 ====================
            case 'getFeedDetail': {
                const { feedId } = params;
                if (!feedId) return fail('参数错误');
                const viewerUid = await requireAuth();

                let feed = await ensureFeedVisible(feedId, viewerUid, { allowOwnerWhenHidden: true, failMessage: '动态不可见' });

                // 检查点赞和收藏状态
                if (viewerUid) {
                    const [likeRes, collectRes] = await Promise.all([
                        likesCol.where({ feed_id: feedId, user_id: viewerUid }).get(),
                        collectsCol.where({ feed_id: feedId, user_id: viewerUid }).get()
                    ]);
                    feed.liked = likeRes.data.length > 0;
                    feed.collected = collectRes.data.length > 0;
                }

                return success({
                    id: feed._id,
                    userId: feed.user_id,
                    nickname: feed.nickname,
                    avatar: feed.avatar,
                    gender: feed.gender,
                    cover: feed.cover,
                    content: feed.content,
                    type: feed.type,
                    level: feed.level,
                    location: feed.location,
                    tags: feed.tags,
                    status: typeof feed.status === 'number' ? feed.status : 1,
                    moderationStatus: feed.moderation_status || 'pass',
                    moderationReason: feed.moderation_reason || '',
                    likeCount: feed.like_count,
                    commentCount: feed.comment_count,
                    giftCount: feed.gift_count,
                    liked: feed.liked || false,
                    collected: feed.collected || false,
                    createdAt: feed.create_date
                });
            }

            default:
                return fail('Unknown action: ' + action);
        }
    } catch (error) {
        console.error('fit-discover-api error:', error);
        return fail(error.message || '服务器错误');
    }
};

'use strict'
const db = uniCloud.database()
const dbCmd = db.command

const notificationsCol = db.collection('fit-notifications')
const usersCol = db.collection('uni-id-users')

// ─── 响应封装 ───
const success = (data, msg = 'success') => ({ code: 0, msg, data })
const fail = (msg, code = -1) => ({ code, msg })

// ─── 鉴权 ───
async function getUid(event, context) {
  try {
    const ctxUid = context && context.CLIENTINFO && context.CLIENTINFO.uid
    if (ctxUid) return ctxUid

    const uniIdCommon = require('uni-id-common')
    const uniID = uniIdCommon.createInstance({ context })
    const token =
      event.uniIdToken ||
      context.uniIdToken ||
      event.token ||
      (event.headers &&
        (event.headers.uniIdToken || event.headers['uni-id-token'])) ||
      (event.params &&
        (event.params.uniIdToken || event.params.token))
    if (!token) return null

    const payload = await uniID.checkToken(token)
    if (payload.errCode === 0) return payload.uid
    return null
  } catch (e) {
    console.error('[fit-notification-api] checkToken error:', e)
    return null
  }
}

exports.main = async (event, context) => {
  const { action, params = {} } = event
  let _uid

  const requireAuth = async () => {
    if (_uid === undefined) _uid = await getUid(event, context)
    return _uid
  }

  try {
    switch (action) {
      // ================================================================
      // getNotifications — 分页拉取当前用户的通知列表
      // 请求: { page, pageSize, lastId? }
      // 响应: { list, hasMore, unreadCount }
      // ================================================================
      case 'getNotifications': {
        const uid = await requireAuth()
        if (!uid) return fail('请先登录')

        const { page = 1, pageSize = 20, lastId } = params
        const limit = Math.min(Math.max(1, pageSize), 50) // 限制每页最多 50
        const skip = (page - 1) * limit

        // 构造查询条件
        const where = { toUserId: uid }
        if (lastId) {
          // 游标分页: 取 createdAt < lastId 对应记录的 createdAt
          try {
            const cursorDoc = await notificationsCol.doc(lastId).get()
            if (cursorDoc.data && cursorDoc.data.length > 0) {
              where.createdAt = dbCmd.lt(cursorDoc.data[0].createdAt)
            }
          } catch (_) {
            // 游标失效时忽略，退回 skip 分页
          }
        }

        // 查询列表
        const listRes = await notificationsCol
          .where(where)
          .orderBy('createdAt', 'desc')
          .skip(lastId ? 0 : skip) // 游标模式不 skip
          .limit(limit + 1) // 多取 1 条判断 hasMore
          .get()

        let list = listRes.data || []
        const hasMore = list.length > limit
        if (hasMore) list = list.slice(0, limit)

        // 格式化
        list = list.map(formatNotification)

        // 未读总数
        const unreadRes = await notificationsCol
          .where({ toUserId: uid, isRead: false })
          .count()
        const unreadCount = unreadRes.total || 0

        return success({ list, hasMore, unreadCount })
      }

      // ================================================================
      // readNotifications — 批量标记已读
      // 请求: { ids: string[] }
      // 响应: { success, unreadCount }
      // ================================================================
      case 'readNotifications': {
        const uid = await requireAuth()
        if (!uid) return fail('请先登录')

        const { ids } = params
        if (!Array.isArray(ids) || ids.length === 0) {
          return fail('参数错误：ids 必须是非空数组')
        }

        // 限制批量大小
        const safeIds = ids.slice(0, 100)

        // 只能标记自己的通知
        await notificationsCol
          .where({
            _id: dbCmd.in(safeIds),
            toUserId: uid,
            isRead: false,
          })
          .update({
            isRead: true,
            readAt: Date.now(),
          })

        // 返回最新未读数
        const unreadRes = await notificationsCol
          .where({ toUserId: uid, isRead: false })
          .count()
        const unreadCount = unreadRes.total || 0

        return success({ success: true, unreadCount })
      }

      // ================================================================
      // getUnreadCount — 仅返回未读数 (轻量)
      // 请求: 空
      // 响应: { unreadCount }
      // ================================================================
      case 'getUnreadCount': {
        const uid = await requireAuth()
        if (!uid) return fail('请先登录')

        const unreadRes = await notificationsCol
          .where({ toUserId: uid, isRead: false })
          .count()

        return success({ unreadCount: unreadRes.total || 0 })
      }

      // ================================================================
      // createNotification — 服务端/管理后台创建通知（内部调用）
      // 请求: { toUserId, type, title, content, meetId?, meetTitle? }
      // 响应: { id }
      // ================================================================
      case 'createNotification': {
        const uid = await requireAuth()
        if (!uid) return fail('请先登录')

        const { toUserId, type, title, content, meetId, meetTitle } = params
        if (!toUserId || !type || !title) {
          return fail('参数错误：toUserId, type, title 必填')
        }

        const validTypes = ['apply', 'accepted', 'rejected', 'system']
        if (!validTypes.includes(type)) {
          return fail(`无效的通知类型: ${type}`)
        }

        const doc = {
          toUserId,
          fromUserId: uid,
          type,
          title: String(title).slice(0, 100),
          content: String(content || '').slice(0, 500),
          meetId: meetId || '',
          meetTitle: meetTitle || '',
          isRead: false,
          readAt: null,
          createdAt: Date.now(),
        }

        const addRes = await notificationsCol.add(doc)
        return success({ id: addRes.id })
      }

      // ================================================================
      // markAllRead — 全部标记已读
      // 请求: 空
      // 响应: { success, updated }
      // ================================================================
      case 'markAllRead': {
        const uid = await requireAuth()
        if (!uid) return fail('请先登录')

        const updateRes = await notificationsCol
          .where({ toUserId: uid, isRead: false })
          .update({
            isRead: true,
            readAt: Date.now(),
          })

        return success({
          success: true,
          updated: updateRes.updated || 0,
          unreadCount: 0,
        })
      }

      default:
        return fail('Unknown action: ' + action)
    }
  } catch (error) {
    console.error('[fit-notification-api] error:', error)
    return fail(error.message || '服务器错误')
  }
}

// ─── 格式化通知文档 → 前端字段 ───
function formatNotification(doc) {
  return {
    id: doc._id,
    toUserId: doc.toUserId || '',
    fromUserId: doc.fromUserId || '',
    type: doc.type || 'system',
    title: doc.title || '',
    content: doc.content || '',
    meetId: doc.meetId || '',
    meetTitle: doc.meetTitle || '',
    isRead: !!doc.isRead,
    createdAt: doc.createdAt || 0,
  }
}

'use strict';
const db = uniCloud.database();
const dbCmd = db.command;

// ──────────────────────────────────────
// 集合引用
// ──────────────────────────────────────
const profilesCol  = db.collection('fit-user-profiles');
const workoutsCol   = db.collection('fit-workout-logs');
const baCol         = db.collection('fit-before-after');
const coachSetCol   = db.collection('fit-coach-settings');
const studentsCol   = db.collection('fit-coach-students');
const incomeCol     = db.collection('fit-income-records');
const convsCol      = db.collection('fit-conversations');
const msgsCol       = db.collection('fit-messages');
const usersCol      = db.collection('uni-id-users');

// ──────────────────────────────────────
// 工具函数
// ──────────────────────────────────────
const success = (data, msg = 'success') => ({ code: 0, msg, data });
const fail    = (msg, code = -1)        => ({ code, msg });

function buildUnreadCountMap(members = [], source = {}) {
	const map = { ...(source || {}) };
	members.forEach(memberId => {
		const current = Number(map[memberId] || 0);
		map[memberId] = Number.isFinite(current) && current > 0 ? current : 0;
	});
	return map;
}

function getUnreadCountForUser(conversation = {}, uid) {
	if (!uid) return 0;
	const unreadMap = buildUnreadCountMap(conversation.members || [], conversation.unread_count_map || {});
	return Number(unreadMap[uid] || 0);
}

/** 获取当月起止时间戳 */
function getMonthRange() {
	const now = new Date();
	const start = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
	const end   = new Date(now.getFullYear(), now.getMonth() + 1, 1).getTime();
	return { start, end };
}

/** 相对时间描述 */
function relativeTime(ts) {
	if (!ts) return '未知';
	const diff = Date.now() - ts;
	const minutes = Math.floor(diff / 60000);
	if (minutes < 1) return '刚刚';
	if (minutes < 60) return minutes + '分钟前';
	const hours = Math.floor(minutes / 60);
	if (hours < 24) return hours + '小时前';
	const days = Math.floor(hours / 24);
	if (days < 30) return days + '天前';
	const months = Math.floor(days / 30);
	return months + '个月前';
}

/** 格式化日期为 MM-DD HH:mm */
function formatDate(ts) {
	if (!ts) return '';
	const d = new Date(ts);
	const M  = String(d.getMonth() + 1).padStart(2, '0');
	const D  = String(d.getDate()).padStart(2, '0');
	const h  = String(d.getHours()).padStart(2, '0');
	const m  = String(d.getMinutes()).padStart(2, '0');
	return `${M}-${D} ${h}:${m}`;
}

// ──────────────────────────────────────
// 主入口
// ──────────────────────────────────────
exports.main = async (event, context) => {
	const { action, params = {} } = event;

	// ── 通过 uni-id-common 验证 token 获取 uid（企业级标准方案） ──
	let uid = null;
	try {
		const uniIdCommon = require('uni-id-common');
		const uniID = uniIdCommon.createInstance({ context });
		const payload = await uniID.checkToken(event.uniIdToken);
		if (payload.errCode === 0) {
			uid = payload.uid;
		}
	} catch (e) {
		console.error('[fit-ucenter-api] checkToken error:', e.message);
	}

	try {
		switch (action) {

			// ==========================================
			// 用户资料
			// ==========================================

			/** 获取当前用户资料 */
			case 'getProfile': {
				if (!uid) return fail('请先登录');

				const res = await profilesCol.where({ uid }).limit(1).get();
				if (res.data && res.data.length > 0) {
					const p = res.data[0];
					return success({
						nickname:   p.nickname || '',
							gender:     p.gender || '',
							age:        typeof p.age === 'number' ? p.age : null,
						city:       p.city || '',
						singleCert: !!p.single_cert,
						gyms:       p.gyms || [],
						coverUrl:   p.cover_url || '',
						avatarUrl:  p.avatar_url || '',
						bio:        p.bio || '',
						isCoach:    !!p.is_coach,
					});
				}

				// 首次访问：从 uni-id-users 拉取基础信息自动建档
				let baseInfo = {};
				try {
					const userRes = await usersCol.doc(uid).field({
						nickname: 1, avatar: 1, gender: 1, avatar_file: 1
					}).get();
					if (userRes.data && userRes.data.length > 0) {
						baseInfo = userRes.data[0];
					}
				} catch (_) { /* ignore */ }

					let derivedGender = '';
					if (baseInfo.gender === 1) derivedGender = '男';
					if (baseInfo.gender === 2) derivedGender = '女';

					const newProfile = {
					uid,
					nickname:   baseInfo.nickname || '',
						gender:     derivedGender,
						age:        null,
					city:       '',
					single_cert: false,
					gyms:       [],
					cover_url:  '',
					avatar_url: baseInfo.avatar || (baseInfo.avatar_file && baseInfo.avatar_file.url) || '',
					bio:        '',
					is_coach:   false,
					create_date: Date.now(),
				};
				await profilesCol.add(newProfile);

				return success({
					nickname:   newProfile.nickname,
					gender:     newProfile.gender,
					age:        newProfile.age,
					city:       newProfile.city,
					singleCert: false,
					gyms:       [],
					coverUrl:   '',
					avatarUrl:  newProfile.avatar_url,
					bio:        '',
					isCoach:    false,
				});
			}

			/** 更新用户资料 */
			case 'updateProfile': {
				if (!uid) return fail('请先登录');

				const {
					nickname, gender, age, city, singleCert,
					gyms, coverUrl, avatarUrl, bio
				} = params;

				// 校验
				if (nickname !== undefined) {
					const trimmed = (nickname || '').trim();
					if (trimmed.length < 2 || trimmed.length > 20) {
						return fail('昵称长度应在2-20之间');
					}
				}
				if (age !== undefined) {
					const n = Number(age);
					if (!n || n < 12 || n > 80) return fail('年龄应在12-80之间');
				}
				if (gyms !== undefined && Array.isArray(gyms) && gyms.length > 6) {
					return fail('健身房最多6个');
				}

				const updateData = { update_date: Date.now() };
				if (nickname   !== undefined) updateData.nickname    = nickname.trim();
				if (gender     !== undefined) updateData.gender      = gender;
				if (age        !== undefined) updateData.age         = Number(age);
				if (city       !== undefined) updateData.city        = (city || '').trim();
				if (singleCert !== undefined) updateData.single_cert = !!singleCert;
				if (gyms       !== undefined) updateData.gyms        = gyms.slice(0, 6);
				if (coverUrl   !== undefined) updateData.cover_url   = coverUrl;
				if (avatarUrl  !== undefined) updateData.avatar_url  = avatarUrl;
				if (bio        !== undefined) updateData.bio         = (bio || '').trim();

				const existing = await profilesCol.where({ uid }).limit(1).get();
				if (existing.data && existing.data.length > 0) {
					await profilesCol.where({ uid }).update(updateData);
				} else {
					await profilesCol.add({ uid, ...updateData, create_date: Date.now() });
				}

				// 同步昵称和头像到 uni-id-users
				const syncFields = {};
				if (updateData.nickname)   syncFields.nickname = updateData.nickname;
				if (updateData.avatar_url) syncFields.avatar   = updateData.avatar_url;
				if (Object.keys(syncFields).length > 0) {
					try { await usersCol.doc(uid).update(syncFields); } catch (_) { /* ignore */ }
				}

				return success(params);
			}

			/** 上传图片到云存储 */
			case 'uploadImage': {
				if (!uid) return fail('请先登录');
				// 实际上传由客户端 uniCloud.uploadFile 完成
				// 此 action 仅用于记录或做额外处理
				const { fileUrl } = params;
				return success({ url: fileUrl });
			}

			// ==========================================
			// 训练统计
			// ==========================================

			/** 获取训练统计 */
			case 'getStats': {
				if (!uid) return fail('请先登录');

				const { start: monthStart } = getMonthRange();

				// 本月训练记录
				const logsRes = await workoutsCol.where({
					uid,
					create_date: dbCmd.gte(monthStart),
				}).get();

				const logs = logsRes.data || [];
				// 统计训练天数（按日去重）
				const daySet = new Set();
				let totalTimes = logs.length;
				let totalCalorie = 0;

				logs.forEach(log => {
					const d = new Date(log.create_date);
					daySet.add(`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`);
					totalCalorie += (log.calorie || 0);
				});

				return success({
					days:    daySet.size,
					times:   totalTimes,
					calorie: totalCalorie,
				});
			}

			/** 记录一次训练 */
			case 'logWorkout': {
				if (!uid) return fail('请先登录');

				const { type = 'gym', duration = 60, calorie = 1, note = '' } = params;

				await workoutsCol.add({
					uid,
					type,
					duration: Math.min(600, Math.max(1, Number(duration) || 60)),
					calorie:  Math.max(0, Number(calorie) || 1),
					note:     (note || '').slice(0, 200),
					create_date: Date.now(),
				});

				// 返回最新统计
				const { start: monthStart } = getMonthRange();
				const logsRes = await workoutsCol.where({
					uid,
					create_date: dbCmd.gte(monthStart),
				}).get();

				const logs = logsRes.data || [];
				const daySet = new Set();
				let totalCalorie = 0;
				logs.forEach(log => {
					const d = new Date(log.create_date);
					daySet.add(`${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`);
					totalCalorie += (log.calorie || 0);
				});

				return success({
					days:    daySet.size,
					times:   logs.length,
					calorie: totalCalorie,
				});
			}

			// ==========================================
			// Before / After 对比照
			// ==========================================

			/** 获取对比照列表 */
			case 'getBeforeAfter': {
				if (!uid) return fail('请先登录');

				const res = await baCol.where({
					uid,
					status: 1,
				}).orderBy('create_date', 'desc').limit(20).get();

				const list = (res.data || []).map(item => ({
					id:     item._id,
					before: item.before,
					after:  item.after,
					note:   item.note || '',
					createdAt: item.create_date,
				}));

				return success(list);
			}

			/** 添加对比照 */
			case 'addBeforeAfter': {
				if (!uid) return fail('请先登录');

				const { before, after, note = '' } = params;
				if (!before || !after) return fail('请提供前后对比照片');

				const addRes = await baCol.add({
					uid,
					before,
					after,
					note: (note || '').slice(0, 200),
					status: 1,
					create_date: Date.now(),
				});

				return success({
					id:     addRes.id,
					before,
					after,
					note,
					createdAt: Date.now(),
				});
			}

			// ==========================================
			// 教练设置
			// ==========================================

			/** 获取教练接单设置 */
			case 'getCoachSettings': {
				if (!uid) return fail('请先登录');

				const res = await coachSetCol.where({ uid }).limit(1).get();
				if (res.data && res.data.length > 0) {
					const s = res.data[0];
					return success({
						available:  s.available !== false,
						price:      s.price || 120,
						skillsText: s.skills_text || '',
						intro:      s.intro || '',
					});
				}

				return success({
					available:  true,
					price:      120,
					skillsText: '',
					intro:      '',
				});
			}

			/** 更新教练接单设置 */
			case 'updateCoachSettings': {
				if (!uid) return fail('请先登录');

				const { available, price, skillsText, intro } = params;

				if (price !== undefined) {
					const p = Number(price);
					if (isNaN(p) || p < 0 || p > 99999) return fail('请输入合理价格');
				}

				const updateData = { update_date: Date.now() };
				if (available  !== undefined) updateData.available   = !!available;
				if (price      !== undefined) updateData.price       = Number(price);
				if (skillsText !== undefined) updateData.skills_text = (skillsText || '').slice(0, 200);
				if (intro      !== undefined) updateData.intro       = (intro || '').slice(0, 500);

				const existing = await coachSetCol.where({ uid }).limit(1).get();
				if (existing.data && existing.data.length > 0) {
					await coachSetCol.where({ uid }).update(updateData);
				} else {
					await coachSetCol.add({ uid, ...updateData, create_date: Date.now() });
				}

				// 同步教练身份到 profile
				try {
					await profilesCol.where({ uid }).update({ is_coach: true, update_date: Date.now() });
				} catch (_) { /* ignore */ }

				return success({ available, price, skillsText, intro });
			}

			// ==========================================
			// 学员管理
			// ==========================================

			/** 获取教练的学员列表 */
			case 'getStudents': {
				if (!uid) return fail('请先登录');

				const res = await studentsCol.where({
					coach_id: uid,
					status: dbCmd.in([0, 1]),
				}).orderBy('last_active_date', 'desc').limit(50).get();

				const list = (res.data || []).map(s => ({
					id:         s.student_id,
					name:       s.student_name || '学员',
					avatar:     s.student_avatar || '',
					level:      s.level || '',
					sessions:   s.total_sessions || 0,
					lastActive: relativeTime(s.last_active_date),
					status:     s.status,
				}));

				return success(list);
			}

			// ==========================================
			// 收入记录
			// ==========================================

			/** 获取教练收入 */
			case 'getIncome': {
				if (!uid) return fail('请先登录');

				const { start: monthStart } = getMonthRange();

				// 本月收入
				const monthRes = await incomeCol.where({
					uid,
					status: 1,
					create_date: dbCmd.gte(monthStart),
				}).get();

				const monthIncome = (monthRes.data || []).reduce((sum, r) => sum + (r.amount || 0), 0);

				// 累计收入
				const totalRes = await incomeCol.where({
					uid,
					status: 1,
				}).get();

				const totalIncome = (totalRes.data || []).reduce((sum, r) => sum + (r.amount || 0), 0);

				// 最近收入明细
				const recordsRes = await incomeCol.where({
					uid,
				}).orderBy('create_date', 'desc').limit(50).get();

				const records = (recordsRes.data || []).map(r => ({
					id:     r._id,
					title:  r.title || '收入',
					date:   formatDate(r.create_date),
					amount: r.amount || 0,
					type:   r.type || 'private_course',
					status: r.status,
				}));

				return success({
					summary: {
						month: monthIncome,
						total: totalIncome,
					},
					records,
				});
			}

			// ==========================================
			// 聊天 - 会话管理
			// ==========================================

			/** 获取或创建与某用户的会话 */
			case 'getOrCreateConversation': {
				if (!uid) return fail('请先登录');

				const { targetUserId } = params;
				if (!targetUserId) return fail('缺少目标用户ID');
				if (targetUserId === uid) return fail('不能与自己聊天');

				// 查找已有会话（成员包含双方）
				const existRes = await convsCol.where({
					members: dbCmd.all([uid, targetUserId]),
				}).limit(1).get();

				if (existRes.data && existRes.data.length > 0) {
					return success({
						conversationId: existRes.data[0]._id,
						isNew: false,
					});
				}

				// 创建新会话
				const addRes = await convsCol.add({
					members:           [uid, targetUserId],
					last_message:      '',
					last_sender_id:    '',
					last_message_date: Date.now(),
					unread_count_map:  { [uid]: 0, [targetUserId]: 0 },
					create_date:       Date.now(),
				});

				return success({
					conversationId: addRes.id,
					isNew: true,
				});
			}

			/** 发送消息 */
			case 'sendMessage': {
				if (!uid) return fail('请先登录');

				const { conversationId, content, type = 'text' } = params;
				if (!conversationId || !content) return fail('消息内容不能为空');

				// 校验会话归属
				const convRes = await convsCol.doc(conversationId).get();
				if (!convRes.data || convRes.data.length === 0) return fail('会话不存在');
				const conv = convRes.data[0];
				if (!conv.members.includes(uid)) return fail('无权操作');
				const targetUserId = (conv.members || []).find(memberId => memberId !== uid) || '';
				const unreadMap = buildUnreadCountMap(conv.members || [], conv.unread_count_map || {});
				if (targetUserId) {
					unreadMap[targetUserId] = Number(unreadMap[targetUserId] || 0) + 1;
				}
				unreadMap[uid] = 0;

				const now = Date.now();
				const msgData = {
					conversation_id: conversationId,
					sender_id:       uid,
					content:         content.trim().slice(0, 2000),
					type,
					read:            false,
					create_date:     now,
					delivered_at:    now,
					read_at:         null,
				};
				await msgsCol.add(msgData);

				// 更新会话摘要
				await convsCol.doc(conversationId).update({
					last_message:      msgData.content.slice(0, 100),
					last_sender_id:    uid,
					last_message_date: now,
					unread_count_map:  unreadMap,
				});

				return success(msgData);
			}

			/** 获取消息列表（支持增量拉取） */
			case 'getMessages': {
				if (!uid) return fail('请先登录');

				const { conversationId, page = 1, pageSize = 30, since = null } = params;
				if (!conversationId) return fail('缺少会话ID');

				// 校验会话归属
				const convRes = await convsCol.doc(conversationId).get();
				if (!convRes.data || convRes.data.length === 0) return fail('会话不存在');
				if (!convRes.data[0].members.includes(uid)) return fail('无权操作');

				let query = msgsCol.where({ conversation_id: conversationId });
				if (since) {
					query = query.where({ create_date: dbCmd.gt(Number(since)) });
				}

				let res;
				if (since) {
					res = await query.orderBy('create_date', 'asc').limit(pageSize).get();
				} else {
					const skip = (page - 1) * pageSize;
					res = await query.orderBy('create_date', 'desc').skip(skip).limit(pageSize).get();
				}

				const currentConversation = convRes.data[0];
				const shouldMarkRead = !!since || Number(page) <= 1;
				const unreadCount = getUnreadCountForUser(currentConversation, uid);
				if (shouldMarkRead && unreadCount > 0) {
					const now = Date.now();
					await msgsCol.where({
						conversation_id: conversationId,
						sender_id: dbCmd.neq(uid),
						read: false,
					}).update({ read: true, read_at: now });

					const unreadMap = buildUnreadCountMap(currentConversation.members || [], currentConversation.unread_count_map || {});
					unreadMap[uid] = 0;
					await convsCol.doc(conversationId).update({ unread_count_map: unreadMap });
				}

				return success(res.data || []);
			}

			case 'getUnreadCount': {
				if (!uid) return fail('请先登录');

				const convRes = await convsCol.where({
					members: dbCmd.elemMatch(dbCmd.eq(uid)),
				}).field({ members: 1, unread_count_map: 1 }).limit(100).get();

				const total = (convRes.data || []).reduce((sum, conv) => {
					return sum + getUnreadCountForUser(conv, uid);
				}, 0);

				return success({ count: total });
			}

			/** 在线心跳与对端在线查询 */
			case 'heartbeat': {
				if (!uid) return fail('请先登录');
				const { targetUserId } = params;
				const now = Date.now();
				await usersCol.doc(uid).update({ last_online: now });

				let targetOnline = false;
				let targetLast = null;
				if (targetUserId) {
					const tRes = await usersCol.doc(targetUserId).field({ last_online: 1 }).get();
					if (tRes.data && tRes.data.length > 0) {
						targetLast = tRes.data[0].last_online || null;
						targetOnline = targetLast && (now - targetLast <= 60000);
					}
				}

				return success({ now, targetOnline, targetLastOnline: targetLast });
			}

			/** 获取当前用户的会话列表（按最近消息倒序） */
			case 'listConversations': {
				if (!uid) return fail('请先登录');

				const { limit = 50 } = params;

				const convRes = await convsCol.where({
					members: dbCmd.elemMatch(dbCmd.eq(uid)),
				}).orderBy('last_message_date', 'desc').limit(limit).get();

				const convs = convRes.data || [];
				if (convs.length === 0) return success([]);

				const targetIds = [...new Set(convs
					.map(c => (c.members || []).find(m => m !== uid))
					.filter(Boolean)
				)];

				// 查询用户信息
				let userMap = {};
				if (targetIds.length > 0) {
					const userRes = await usersCol.where({ _id: dbCmd.in(targetIds) }).field({
						nickname: 1,
						avatar: 1,
						avatar_file: 1,
					}).get();
					userMap = (userRes.data || []).reduce((map, u) => {
						map[u._id] = u;
						return map;
					}, {});
				}

				const result = convs.map(conv => {
					const partnerId = (conv.members || []).find(m => m !== uid) || '';
					const user = userMap[partnerId] || {};
					const avatar = (user.avatar_file && user.avatar_file.url) || user.avatar || '';
					return {
						conversationId: conv._id,
						targetUserId: partnerId,
						nickname: user.nickname || '用户',
						avatar,
						lastMessage: conv.last_message || '',
						lastMessageDate: conv.last_message_date || conv.create_date,
						unread: getUnreadCountForUser(conv, uid),
					};
				});

				return success(result);
			}

			default:
				return fail('Unknown action: ' + action);
		}
	} catch (error) {
		console.error('fit-ucenter-api error:', error);
		return fail(error.message || '服务器错误');
	}
};

'use strict';
const db = uniCloud.database();

/**
 * 获取 Discover 列表（公共可见）
 */
exports.main = async (event, context) => {
  try {
    const page = Math.max(1, Number(event.page) || 1);
    const pageSize = Math.max(1, Math.min(50, Number(event.pageSize) || 15));
    const skip = (page - 1) * pageSize;

    const collection = db.collection('discovers');

    const listRes = await collection
      .orderBy('createdAt', 'desc')
      .skip(skip)
      .limit(pageSize)
      .get();

    const totalRes = await collection.count();

    const list = (listRes.data || []).map(item => ({
      id: item._id,
      userId: item.user_id || item.publisherId || item._openid,
      nickname: item.nickname || item.publisherName || '用户',
      avatar: item.avatar || item.publisherAvatar || '',
      content: item.content || '',
      type: item.type || 'gym',
      level: item.level || 'beginner',
      gender: item.gender || 'unknown',
      location: item.location || item.city || '',
      distanceKm: item.distanceKm,
      cover: item.cover || '',
      tags: Array.isArray(item.tags) ? item.tags : [],
      likeCount: item.like_count || item.likeCount || 0,
      commentCount: item.comment_count || item.commentCount || 0,
      giftCount: item.gift_count || item.giftCount || 0,
      createdAt: item.createdAt || item.create_date || Date.now()
    }));

    const hasMore = skip + list.length < (totalRes.total || 0);

    return {
      code: 0,
      msg: 'success',
      data: {
        list,
        page,
        pageSize,
        hasMore,
        total: totalRes.total || 0
      }
    };
  } catch (error) {
    console.error('[getDiscoverList] error:', error);
    return { code: -1, msg: '获取失败' };
  }
};

'use strict';
const db = uniCloud.database();

const maskToken = (token) => {
  if (!token) return '';
  const str = String(token);
  if (str.length <= 12) return `${str.slice(0, 3)}***${str.slice(-2)}`;
  return `${str.slice(0, 6)}...${str.slice(-4)}(len:${str.length})`;
};

const resolveUid = async (event, context) => {
  try {
    const ctxUid = context && context.CLIENTINFO && context.CLIENTINFO.uid;
    if (ctxUid) return ctxUid;
    const uniIdCommon = require('uni-id-common');
    const uniID = uniIdCommon.createInstance({ context });
    const token = event.uniIdToken || context.uniIdToken || event.token || (event.headers && (event.headers.uniIdToken || event.headers['uni-id-token']));
    console.log('[publishDiscover] auth token received:', {
      fromEventUniIdToken: !!event.uniIdToken,
      fromContextUniIdToken: !!context.uniIdToken,
      fromEventToken: !!event.token,
      fromHeadersToken: !!(event.headers && (event.headers.uniIdToken || event.headers['uni-id-token'])),
      tokenMasked: maskToken(token)
    });
    if (!token) return '';
    const payload = await uniID.checkToken(token);
    console.log('[publishDiscover] checkToken result:', {
      errCode: payload && payload.errCode,
      errMsg: payload && payload.errMsg,
      uid: payload && payload.uid,
      tokenExpired: payload && payload.tokenExpired
    });
    return payload.errCode === 0 ? payload.uid : '';
  } catch (error) {
    console.warn('[publishDiscover] resolveUid failed:', error);
    return '';
  }
};

/**
 * 发布 Discover 动态
 * 鉴权：使用 uni-id token uid
 */
exports.main = async (event, context) => {
  try {
    const uid = await resolveUid(event, context);
    if (!uid) {
      return { code: 401, msg: '未登录，无法发布', message: '未登录，无法发布' };
    }

    const content = String(event.content || '').trim();
    if (!content) {
      return { code: -1, msg: '内容不能为空' };
    }

    const publisherName = String(event.publisherName || '').trim() || '用户';
    const publisherAvatar = String(event.publisherAvatar || '').trim() || '';

    const doc = {
      publisherId: uid,
      user_id: uid,
      publisherName,
      publisherAvatar,
      nickname: publisherName,
      avatar: publisherAvatar,
      content,
      type: event.type || 'gym',
      level: event.level || 'beginner',
      gender: event.gender || 'unknown',
      location: event.location || '',
      location_geo: event.lat != null && event.lng != null ? { type: 'Point', coordinates: [event.lng, event.lat] } : null,
      cover: event.photo || '',
      tags: Array.isArray(event.tags) ? event.tags : [],
      city: event.city || '',
      like_count: 0,
      comment_count: 0,
      gift_count: 0,
      createdAt: db.serverDate(),
      status: 1
    };

    const res = await db.collection('discovers').add(doc);

    return {
      code: 0,
      msg: 'success',
      message: '发布成功',
      data: {
        id: res.id,
        ...doc
      }
    };
  } catch (error) {
    console.error('[publishDiscover] error:', error);
    return { code: -1, msg: '发布失败，请稍后重试' };
  }
};
